            return [best[0], best[1]]

    # Fallback: move away from opponent if possible
    away = None
    mind = -1
    for dx, dy in legal:
        nx, ny = sx + dx, sy + dy
        d2 = max(abs(ox - nx), abs(oy - ny))
        if d2 > mind:
            mind = d2
            away = (dx, dy)
    if away:
        return [away[0], away[1]]

    return [0, 0]
